// Calculate this week's date range (Monday to today)
const now = new Date();
const today = now.toISOString().split('T')[0];

const dayOfWeek = now.getDay();
const daysSinceMonday = dayOfWeek === 0 ? 6 : dayOfWeek - 1;
const thisWeekStart = new Date(now.getTime() - daysSinceMonday * 24 * 60 * 60 * 1000);
const thisWeekStartStr = thisWeekStart.toISOString().split('T')[0];

// Previous week for comparison
const prevWeekStart = new Date(thisWeekStart.getTime() - 7 * 24 * 60 * 60 * 1000);
const prevWeekEnd = new Date(thisWeekStart.getTime() - 1 * 24 * 60 * 60 * 1000);
const prevWeekStartStr = prevWeekStart.toISOString().split('T')[0];
const prevWeekEndStr = prevWeekEnd.toISOString().split('T')[0];

return [{ json: {
  today,
  thisWeekStart: thisWeekStartStr,
  prevWeekStart: prevWeekStartStr,
  prevWeekEnd: prevWeekEndStr,
  nowIso: now.toISOString()
} }];

// Assemble the comprehensive "What Got Smarter" weekly digest
// Reads stored reports from TG-114 (revenue), TG-115 (A/B), TG-116 (ads)
// Plus A/B winners and intelligence metrics for context

const dates = $('Calculate Week Range').first().json;
const reportsResponse = $('Fetch Weekly Reports').first().json;
const winnersResponse = $('Fetch A/B Winners').first().json;
const metricsResponse = $('Fetch Intelligence Metrics').first().json;

const reports = reportsResponse.body || reportsResponse || [];
const winners = winnersResponse.body || winnersResponse || [];
const allMetrics = metricsResponse.body || metricsResponse || [];

// Parse sub-reports by type
const reportsByType = {};
if (Array.isArray(reports)) {
  for (const r of reports) {
    if (!reportsByType[r.report_type]) reportsByType[r.report_type] = [];
    reportsByType[r.report_type].push(r.report_data || {});
  }
}

// --- Extract key data from sub-reports ---

// Revenue (from TG-114)
const revenueReports = reportsByType['revenue_attribution'] || [];
const latestRevenue = revenueReports[0] || {};
const weekRevenue = latestRevenue.total_revenue || 0;
const weekLeads = latestRevenue.total_leads || latestRevenue.leads_count || 0;

// A/B test results (from TG-115)
const abReports = reportsByType['ab_test_results'] || [];
const latestAB = abReports[0] || {};
const activeTests = latestAB.active_tests || 0;
const completedTests = latestAB.completed_this_week || 0;

// Ad performance (from TG-116)
const adReports = reportsByType['ad_performance'] || [];
const latestAds = adReports[0] || {};
const adSpend = latestAds.total_spend || 0;
const adConversions = latestAds.total_conversions || 0;
const adROAS = latestAds.roas || 0;

// --- Compute weekly KPI trends from intelligence_metrics ---

function getMetricsByWeek(metrics, weekStart, weekEnd) {
  const filtered = Array.isArray(metrics) ? metrics.filter(m => m.metric_date >= weekStart && m.metric_date <= weekEnd) : [];
  const byName = {};
  for (const m of filtered) {
    if (!byName[m.metric_name]) byName[m.metric_name] = [];
    byName[m.metric_name].push(parseFloat(m.metric_value) || 0);
  }
  // Average each metric
  const result = {};
  for (const [name, vals] of Object.entries(byName)) {
    result[name] = vals.reduce((s, v) => s + v, 0) / vals.length;
  }
  return result;
}

const thisWeekMetrics = getMetricsByWeek(allMetrics, dates.thisWeekStart, dates.today);
const prevWeekMetrics = getMetricsByWeek(allMetrics, dates.prevWeekStart, dates.prevWeekEnd);

function fmt(n, decimals) {
  if (n === undefined || n === null) return '—';
  decimals = decimals || 0;
  return Number(n).toLocaleString('en-US', { minimumFractionDigits: decimals, maximumFractionDigits: decimals });
}

function wow(current, previous) {
  if (!previous || previous === 0) return current > 0 ? '+100%' : '—';
  const pct = ((current - previous) / Math.abs(previous)) * 100;
  const sign = pct >= 0 ? '+' : '';
  return `${sign}${pct.toFixed(1)}%`;
}

// Count anomalies from metrics that deviate >25% from previous week
let anomalyCount = 0;
const anomalyItems = [];
for (const [name, thisVal] of Object.entries(thisWeekMetrics)) {
  const prevVal = prevWeekMetrics[name];
  if (prevVal && prevVal !== 0) {
    const deviation = Math.abs((thisVal - prevVal) / prevVal) * 100;
    if (deviation > 25) {
      anomalyCount++;
      const direction = thisVal > prevVal ? 'up' : 'down';
      const severity = deviation > 50 ? 'critical' : 'warning';
      anomalyItems.push({
        severity,
        message: `${name.replace(/_/g, ' ')}: ${direction} ${deviation.toFixed(0)}% (${fmt(prevVal, 1)} -> ${fmt(thisVal, 1)})`
      });
    }
  }
}

// --- Build TG-118 sections ---

// 1. Top-level metrics
const topMetrics = [
  { label: 'Revenue', value: weekRevenue > 0 ? `$${fmt(weekRevenue, 2)}` : '—', change: '' },
  { label: 'Leads', value: weekLeads > 0 ? fmt(weekLeads) : '—', change: '' },
  { label: 'Active A/B Tests', value: fmt(activeTests), change: '' },
  { label: 'Anomalies', value: fmt(anomalyCount), change: '' }
];

// 2. Highlights — "What Got Smarter"
const highlights = [];

// A/B winners deployed
if (Array.isArray(winners) && winners.length > 0) {
  for (const w of winners) {
    highlights.push(`A/B Winner: "${w.test_name}" — variant ${w.winner || 'selected'} deployed (${w.channel || 'unknown'} channel)`);
  }
} else if (completedTests > 0) {
  highlights.push(`${completedTests} A/B test(s) completed this week`);
}

// Revenue insights
if (weekRevenue > 0) {
  highlights.push(`Revenue tracked: $${fmt(weekRevenue, 2)} from ${fmt(weekLeads)} leads`);
}

// Ad performance
if (adSpend > 0) {
  highlights.push(`Ad spend: $${fmt(adSpend, 2)} with ${fmt(adConversions)} conversions (${fmt(adROAS, 2)}x ROAS)`);
} else if (adReports.length > 0) {
  highlights.push('Google Ads: No active campaigns this week');
}

// Fallback if nothing
if (highlights.length === 0) {
  highlights.push('Intelligence layer active — collecting baseline data');
  highlights.push('Sub-reports will populate as TG-107/108/109 accumulate daily metrics');
}

// 3. Key Numbers table (this week vs last week)
const keyMetricNames = ['leads_total', 'revenue', 'conversion_rate', 'sms_delivered', 'email_opened', 'leads_google'];
const tableHeaders = ['Metric', 'This Week', 'Last Week', 'Change'];
const tableRows = [];
for (const name of keyMetricNames) {
  const thisVal = thisWeekMetrics[name];
  const prevVal = prevWeekMetrics[name];
  if (thisVal !== undefined || prevVal !== undefined) {
    const isRate = name.includes('rate');
    const isDollar = name === 'revenue';
    const formatVal = (v) => {
      if (v === undefined) return '—';
      if (isDollar) return `$${fmt(v, 2)}`;
      if (isRate) return `${fmt(v, 1)}%`;
      return fmt(v, 0);
    };
    tableRows.push([
      name.replace(/_/g, ' ').replace(/\b\w/g, l => l.toUpperCase()),
      formatVal(thisVal),
      formatVal(prevVal),
      thisVal !== undefined && prevVal !== undefined ? wow(thisVal, prevVal) : '—'
    ]);
  }
}

// 4. Actions — "What To Do This Week"
const actions = [];

if (Array.isArray(winners) && winners.length > 0) {
  actions.push('Review A/B test winners and verify variant deployment across workflows');
}

if (activeTests > 0) {
  actions.push(`Monitor ${activeTests} active A/B test(s) — check sample sizes approaching minimum`);
} else {
  actions.push('Consider seeding new A/B tests for SMS copy, email subject lines, or ad creatives');
}

if (adSpend > 0 && adROAS < 2) {
  actions.push(`Ad ROAS at ${fmt(adROAS, 2)}x — review campaign targeting and bid strategy`);
} else if (adSpend > 0) {
  actions.push('Ad performance healthy — consider testing new ad copy or expanding keywords');
}

if (anomalyCount > 0) {
  actions.push(`Investigate ${anomalyCount} KPI anomal${anomalyCount === 1 ? 'y' : 'ies'} from TG-110 alerts`);
}

if (weekLeads > 0 && weekRevenue === 0) {
  actions.push('Leads coming in but no revenue attributed — follow up on open quotes');
}

if (actions.length === 0) {
  actions.push('Continue monitoring — intelligence layer building baseline data');
}

// --- Assemble sections ---
const sections = [
  { type: 'metrics', title: 'This Week at a Glance', items: topMetrics },
  { type: 'highlights', title: 'What Got Smarter', items: highlights }
];

if (tableRows.length > 0) {
  sections.push({ type: 'table', title: 'Key Numbers', headers: tableHeaders, rows: tableRows });
}

if (anomalyItems.length > 0) {
  sections.push({ type: 'anomalies', title: 'KPI Anomalies', items: anomalyItems });
}

sections.push({ type: 'actions', title: 'What To Do This Week', items: actions });

return [{ json: {
  report_title: 'What Got Smarter This Week',
  report_subtitle: `${dates.thisWeekStart} to ${dates.today} | TotalGuard Intelligence Digest`,
  sections,
  summary: {
    week_start: dates.thisWeekStart,
    week_end: dates.today,
    revenue: weekRevenue,
    leads: weekLeads,
    active_ab_tests: activeTests,
    completed_ab_tests: completedTests,
    ab_winners: Array.isArray(winners) ? winners.length : 0,
    ad_spend: adSpend,
    ad_conversions: adConversions,
    ad_roas: adROAS,
    anomaly_count: anomalyCount,
    sub_reports_found: Object.keys(reportsByType).length,
    sub_report_types: Object.keys(reportsByType)
  }
} }];
